import { ref } from 'vue'
import { ElMessage } from 'element-plus'
import profile from '@/api/profile'

export function useProfileData() {
  const loading = ref(false)
  const basicInfo = ref({})
  const profileData = ref({})
  const completionData = ref({
    total_score: 0,
    dimensions: {},
    suggestions: []
  })

  // 获取基本信息
  const fetchBasicInfo = async () => {
    try {
      loading.value = true
      const response = await profile.getBasicInfo()
      console.log('基本信息响应:', response)

      // 直接使用响应数据
      if (response?.data) {
        basicInfo.value = response.data
        profileData.value = { 
          ...profileData.value, 
          basic: response.data 
        }
      }
    } catch (error) {
      console.error('获取基本信息失败:', error)
      ElMessage.error('获取基本信息失败，请稍后重试')
    } finally {
      loading.value = false
    }
  }

  // 获取完整度数据
  const fetchCompletionData = async () => {
    try {
      loading.value = true
      const response = await profile.getCompleteness()
      if (response?.data?.code === 200) {
        completionData.value = {
          total_score: response.data.data?.total_score || 0,
          dimensions: response.data.data?.dimensions || {},
          suggestions: response.data.data?.suggestions || []
        }
      }
    } catch (error) {
      console.error('获取完整度数据失败:', error)
      ElMessage.error('获取完整度数据失败，请稍后重试')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    basicInfo,
    profileData,
    completionData,
    fetchBasicInfo,
    fetchCompletionData
  }
}
